export interface SurfaceReadyEvent {
  metadata: SurfaceMetadata;
  transport: SurfaceTransport;
}

export function validateSurfaceReadyEvent(value: unknown): value is SurfaceReadyEvent {
  if (!isRecord(value) || !exactKeys(value, ["metadata", "transport"], [])) return false;
  if (!(validateSurfaceMetadata(value.metadata))) return false;
  if (!(validateSurfaceTransport(value.transport))) return false;
  const surface = value as unknown as SurfaceReadyEvent;
const metadata = surface.metadata;
if (metadata.id === 0n || metadata.lease_token === 0n || metadata.owner.worker === 0n || metadata.owner.session === 0n || metadata.generation === 0n || metadata.renderer_epoch === 0 || metadata.plan_id === 0n) return false;
if (!metadata.render_config.some((byte) => byte !== 0) || !metadata.plan_hash.some((byte) => byte !== 0) || !metadata.scene_hash.some((byte) => byte !== 0) || !metadata.decision_hash.some((byte) => byte !== 0)) return false;
if (metadata.width === 0 || metadata.height === 0 || metadata.stride === 0 || metadata.region.width === 0 || metadata.region.height === 0) return false;
const stride = BigInt(metadata.stride);
const minimumStride = BigInt(metadata.width) * 4n;
if (stride < minimumStride || stride % 4n !== 0n) return false;
const layoutBytes = stride * BigInt(metadata.height);
if (metadata.byte_length !== layoutBytes) return false;
const rangeEnd = metadata.byte_offset + metadata.byte_length;
if (rangeEnd > 0xffffffffffffffffn) return false;
let regionLength: bigint | undefined;
switch (surface.transport.kind) {
case "BrowserArrayBuffer":
if (metadata.alpha !== AlphaMode.Straight) return false;
regionLength = surface.transport.buffer_length;
break;
case "BrowserImageBitmap":
if (metadata.alpha !== AlphaMode.Premultiplied || surface.transport.width !== metadata.width || surface.transport.height !== metadata.height || metadata.byte_offset !== 0n || metadata.stride !== metadata.width * 4) return false;
break;
case "BrowserSharedArrayBuffer":
if (metadata.alpha !== AlphaMode.Straight || surface.transport.publication_epoch === 0 || surface.transport.fence_byte_offset % 4n !== 0n) return false;
if (surface.transport.fence_byte_offset > MAX_U64 - 4n || surface.transport.fence_byte_offset + 4n > surface.transport.buffer_length) return false;
if (!(surface.transport.fence_byte_offset + 4n <= metadata.byte_offset || surface.transport.fence_byte_offset >= rangeEnd)) return false;
regionLength = surface.transport.buffer_length;
break;
}
if (regionLength !== undefined && rangeEnd > regionLength) return false;
  return true;
}

