export type SurfaceTransport =
  | { kind: "BrowserArrayBuffer"; slot: number; buffer_length: bigint }
  | { kind: "BrowserImageBitmap"; slot: number; width: number; height: number }
  | { kind: "BrowserSharedArrayBuffer"; attachment_slot: number; buffer_length: bigint; fence_byte_offset: bigint; publication_epoch: number }
;

export function validateSurfaceTransport(value: unknown): value is SurfaceTransport {
  if (!isRecord(value) || typeof value.kind !== "string") return false;
  switch (value.kind) {
    case "BrowserArrayBuffer": return exactKeys(value, ["kind", "slot", "buffer_length"], []) && isU16(value.slot) && isU64(value.buffer_length);
    case "BrowserImageBitmap": return exactKeys(value, ["kind", "slot", "width", "height"], []) && isU16(value.slot) && isU32(value.width) && isU32(value.height);
    case "BrowserSharedArrayBuffer": return exactKeys(value, ["kind", "attachment_slot", "buffer_length", "fence_byte_offset", "publication_epoch"], []) && isU16(value.attachment_slot) && isU64(value.buffer_length) && isU64(value.fence_byte_offset) && isU32(value.publication_epoch);
    default: return false;
  }
}

