export function redactSurfaceTransport(value: SurfaceTransport): Readonly<Record<string, unknown>> {
  switch (value.kind) {
    case "BrowserArrayBuffer": return {
      kind: "BrowserArrayBuffer",
      slot: value.slot,
      buffer_length: value.buffer_length,
    };
    case "BrowserImageBitmap": return {
      kind: "BrowserImageBitmap",
      slot: value.slot,
      width: value.width,
      height: value.height,
    };
    case "BrowserSharedArrayBuffer": return {
      kind: "BrowserSharedArrayBuffer",
      attachment_slot: value.attachment_slot,
      buffer_length: value.buffer_length,
      fence_byte_offset: value.fence_byte_offset,
      publication_epoch: value.publication_epoch,
    };
  }
}

