export interface CommandEnvelope { header: EnvelopeHeader; correlation: Correlation; command: Command }
export interface EventEnvelope { header: EnvelopeHeader; correlation: Correlation; event: Event }

const CONNECTION_CONTEXT_BRAND: unique symbol = Symbol("EngineProtocolConnection");
export type ProtocolValidationErrorCode = "InvalidHandshake" | "InvalidEnvelope" | "NonMonotonicSequence";
export interface ProtocolValidationError { readonly code: ProtocolValidationErrorCode }
export type ProtocolValidationResult<T> = Readonly<{ ok: true; value: T }> | Readonly<{ ok: false; error: Readonly<ProtocolValidationError> }>;
const protocolValidationOk = <T>(value: T): ProtocolValidationResult<T> => Object.freeze({ ok: true as const, value });
const protocolValidationError = <T>(code: ProtocolValidationErrorCode): ProtocolValidationResult<T> => Object.freeze({ ok: false as const, error: Object.freeze({ code }) });
export interface CompatibleHandshake {
readonly [CONNECTION_CONTEXT_BRAND]: true;
readonly minor: number;
readonly capabilities: bigint;
readonly max_message_bytes: number;
readonly max_transfer_slots: number;
}
export function negotiateHandshake(localInput: unknown, peerInput: unknown): CompatibleHandshake | undefined {
if (!validateProtocolHello(localInput) || !validateProtocolHello(peerInput)) return undefined;
const local = snapshotProtocolHello(localInput);
const peer = snapshotProtocolHello(peerInput);
const opposite = (local.endpoint_role === EndpointRole.Host && peer.endpoint_role === EndpointRole.Engine)
|| (local.endpoint_role === EndpointRole.Engine && peer.endpoint_role === EndpointRole.Host);
if (!opposite || local.minor !== peer.minor || !fixedBytesEqual(local.schema_hash, SCHEMA_HASH) || !fixedBytesEqual(peer.schema_hash, SCHEMA_HASH)) return undefined;
if ((local.capabilities.mandatory & ~peer.capabilities.supported) !== 0n || (peer.capabilities.mandatory & ~local.capabilities.supported) !== 0n) return undefined;
return Object.freeze({
[CONNECTION_CONTEXT_BRAND]: true as const,
minor: local.minor,
capabilities: local.capabilities.supported & peer.capabilities.supported & KNOWN_ENDPOINT_CAPABILITIES,
max_message_bytes: Math.min(local.max_message_bytes, peer.max_message_bytes),
max_transfer_slots: Math.min(local.max_transfer_slots, peer.max_transfer_slots),
});
}
export function negotiateHandshakeResult(localInput: unknown, peerInput: unknown): ProtocolValidationResult<CompatibleHandshake> {
const value = negotiateHandshake(localInput, peerInput);
return value === undefined ? protocolValidationError("InvalidHandshake") : protocolValidationOk(value);
}
export function validateHandshakeTranscript(hostHello: Command, engineHello: Event, hostAccept: Command, engineReady: Event): CompatibleHandshake | undefined {
if (hostHello.type !== "Hello" || engineHello.type !== "EngineHello" || hostAccept.type !== "HelloAccept" || engineReady.type !== "Ready") return undefined;
if (hostHello.payload.hello.endpoint_role !== EndpointRole.Host || engineHello.payload.hello.endpoint_role !== EndpointRole.Engine) return undefined;
const connection = negotiateHandshake(hostHello.payload.hello, engineHello.payload.hello);
if (connection === undefined || hostAccept.payload.negotiated_minor !== connection.minor || engineReady.payload.negotiated_minor !== connection.minor) return undefined;
if (!fixedBytesEqual(hostAccept.payload.schema_hash, SCHEMA_HASH) || !fixedBytesEqual(engineReady.payload.schema_hash, SCHEMA_HASH) || engineReady.payload.worker === 0n || engineReady.payload.execution_capabilities.supported !== engineHello.payload.execution_capabilities.supported) return undefined;
return connection;
}
export interface PendingSequenceCommit { commit(): boolean }
export class EnvelopeSequenceTracker {
private lastAcceptedValue: bigint | undefined;
get lastAccepted(): bigint | undefined { return this.lastAcceptedValue; }
pending(candidate: bigint): PendingSequenceCommit | undefined {
if (candidate === 0n || (this.lastAcceptedValue !== undefined && candidate <= this.lastAcceptedValue)) return undefined;
let consumed = false;
return Object.freeze({ commit: (): boolean => {
if (consumed) return false;
consumed = true;
if (this.lastAcceptedValue !== undefined && candidate <= this.lastAcceptedValue) return false;
this.lastAcceptedValue = candidate;
return true;
}});
}
}
const correlationRequirementMet = (present: boolean, requirement: CorrelationRequirement): boolean => requirement === "required" ? present : requirement === "optional" ? true : !present;
const validateDescriptorCorrelation = (correlation: Correlation, descriptor: MessageDescriptor): boolean => {
if (correlation.worker === 0n || correlation.session === 0n || correlation.request === 0n || correlation.generation === 0n) return false;
return correlationRequirementMet(true, descriptor.correlation_shape.worker)
&& correlationRequirementMet(correlation.session !== undefined, descriptor.correlation_shape.session)
&& correlationRequirementMet(correlation.request !== undefined, descriptor.correlation_shape.request)
&& correlationRequirementMet(correlation.generation !== undefined, descriptor.correlation_shape.generation);
};
const validateTransferBinding = (message: Command | Event, transferSlots: number, descriptor: MessageDescriptor, connection: CompatibleHandshake): boolean => {
if (!isU16(transferSlots) || transferSlots > connection.max_transfer_slots || transferSlots < descriptor.min_transfer_slots || transferSlots > descriptor.max_transfer_slots) return false;
if ((descriptor.required_capability & ~connection.capabilities) !== 0n) return false;
switch (message.type) {
case "ProvideData": return message.payload.segments.length === transferSlots && message.payload.segments.every((segment, index) => segment.slot === index);
case "SurfaceReady": {
const transport = message.payload.transport;
if ((surfaceTransportRequiredCapability(transport) & ~connection.capabilities) !== 0n) return false;
switch (transport.kind) {
case "BrowserArrayBuffer":
case "BrowserImageBitmap": return transferSlots === 1 && transport.slot < transferSlots;
case "BrowserSharedArrayBuffer": return transferSlots === 1 && transport.attachment_slot < transferSlots;
}
}
default: return true;
}
};
export function validateProvideDataTransferLengths(command: ProvideDataCommand, transferLengths: readonly bigint[]): boolean {
return transferLengths.length > 0
&& transferLengths.length === command.segments.length
&& transferLengths.length <= MAX_TRANSFER_SLOTS
&& command.segments.every((segment, index) => segment.slot === index
&& isU64(transferLengths[index])
&& transferLengths[index] === segment.byte_length);
}
const validatePayloadCorrelation = (correlation: Correlation, message: Command | Event): boolean => {
switch (message.type) {
case "SetViewport": return correlation.generation === message.payload.viewport.generation;
case "Cancel": return correlation.request === message.payload.target;
case "Ready": return correlation.worker === message.payload.worker;
case "DocumentReady": return correlation.session === undefined || correlation.session === message.payload.session;
case "SurfaceReady": return correlation.worker === message.payload.metadata.owner.worker
&& correlation.session === message.payload.metadata.owner.session
&& correlation.generation === message.payload.metadata.generation;
case "RequestCancelled": return correlation.request === message.payload.target;
case "SessionClosed": return correlation.session === message.payload.session;
case "WorkerStopped": return correlation.worker === message.payload.worker;
default: return true;
}
};
const validateEnvelopeDescriptor = (header: EnvelopeHeader, correlation: Correlation, message: Command | Event, kind: MessageKind, transferSlots: number, actualPayloadBytes: number, connection: CompatibleHandshake): boolean => {
const descriptor = descriptorById(header.message_type);
return connection[CONNECTION_CONTEXT_BRAND] === true
&& descriptor !== undefined
&& descriptor.kind === kind
&& descriptor.name === message.type
&& header.minor === connection.minor
&& isU32(actualPayloadBytes)
&& actualPayloadBytes === header.payload_len
&& actualPayloadBytes <= connection.max_message_bytes
&& validateDescriptorCorrelation(correlation, descriptor)
&& validateTransferBinding(message, transferSlots, descriptor, connection)
&& validatePayloadCorrelation(correlation, message);
};
export function validateEnvelopeHeaderForMinor(value: unknown, negotiatedMinor: number): value is EnvelopeHeader {
return Number.isInteger(negotiatedMinor)
&& negotiatedMinor === PROTOCOL_MINOR
&& validateEnvelopeHeader(value)
&& value.minor === negotiatedMinor;
}
export interface PendingCommandEnvelope { readonly envelope: CommandEnvelope; commitSequence(): boolean }
export interface PendingEventEnvelope { readonly envelope: EventEnvelope; commitSequence(): boolean }
export function beginValidateCommandEnvelope(value: unknown, transferSlots: number, actualPayloadBytes: number, connection: CompatibleHandshake, sequence: EnvelopeSequenceTracker): PendingCommandEnvelope | undefined {
if (!isRecord(value) || !exactKeys(value, ["header", "correlation", "command"], []) || !validateEnvelopeHeaderForMinor(value.header, connection.minor) || !validateCorrelation(value.correlation) || !validateCommand(value.command)) return undefined;
const input = value as unknown as CommandEnvelope;
const envelope = Object.freeze({ header: snapshotEnvelopeHeader(input.header), correlation: snapshotCorrelation(input.correlation), command: snapshotCommand(input.command) });
if (!validateEnvelopeDescriptor(envelope.header, envelope.correlation, envelope.command, "command", transferSlots, actualPayloadBytes, connection)) return undefined;
const pending = sequence.pending(envelope.header.sequence);
return pending === undefined ? undefined : Object.freeze({ envelope, commitSequence: (): boolean => pending.commit() });
}
export function beginValidateEventEnvelope(value: unknown, transferSlots: number, actualPayloadBytes: number, connection: CompatibleHandshake, sequence: EnvelopeSequenceTracker): PendingEventEnvelope | undefined {
if (!isRecord(value) || !exactKeys(value, ["header", "correlation", "event"], []) || !validateEnvelopeHeaderForMinor(value.header, connection.minor) || !validateCorrelation(value.correlation) || !validateEvent(value.event)) return undefined;
const input = value as unknown as EventEnvelope;
const envelope = Object.freeze({ header: snapshotEnvelopeHeader(input.header), correlation: snapshotCorrelation(input.correlation), event: snapshotEvent(input.event) });
if (!validateEnvelopeDescriptor(envelope.header, envelope.correlation, envelope.event, "event", transferSlots, actualPayloadBytes, connection)) return undefined;
const pending = sequence.pending(envelope.header.sequence);
return pending === undefined ? undefined : Object.freeze({ envelope, commitSequence: (): boolean => pending.commit() });
}
export function beginValidateCommandEnvelopeResult(value: unknown, transferSlots: number, actualPayloadBytes: number, connection: CompatibleHandshake, sequence: EnvelopeSequenceTracker): ProtocolValidationResult<PendingCommandEnvelope> {
const pending = beginValidateCommandEnvelope(value, transferSlots, actualPayloadBytes, connection, sequence);
if (pending !== undefined) return protocolValidationOk(pending);
if (isRecord(value) && isRecord(value.header) && typeof value.header.sequence === "bigint" && (value.header.sequence === 0n || (sequence.lastAccepted !== undefined && value.header.sequence <= sequence.lastAccepted))) return protocolValidationError("NonMonotonicSequence");
return protocolValidationError("InvalidEnvelope");
}
export function beginValidateEventEnvelopeResult(value: unknown, transferSlots: number, actualPayloadBytes: number, connection: CompatibleHandshake, sequence: EnvelopeSequenceTracker): ProtocolValidationResult<PendingEventEnvelope> {
const pending = beginValidateEventEnvelope(value, transferSlots, actualPayloadBytes, connection, sequence);
if (pending !== undefined) return protocolValidationOk(pending);
if (isRecord(value) && isRecord(value.header) && typeof value.header.sequence === "bigint" && (value.header.sequence === 0n || (sequence.lastAccepted !== undefined && value.header.sequence <= sequence.lastAccepted))) return protocolValidationError("NonMonotonicSequence");
return protocolValidationError("InvalidEnvelope");
}

// Canonical fixed_le_v1 typed payload codec.
export const DEFAULT_PAYLOAD_CODEC_MAX_DEPTH = 64 as const;
export const DEFAULT_PAYLOAD_CODEC_MAX_CONTAINER_ITEMS = 1048576 as const;
export const DEFAULT_PAYLOAD_CODEC_LIMITS: Readonly<PayloadCodecLimits> = Object.freeze({ maxDepth: DEFAULT_PAYLOAD_CODEC_MAX_DEPTH, maxBytes: 16777216, maxContainerItems: DEFAULT_PAYLOAD_CODEC_MAX_CONTAINER_ITEMS });

export type PayloadCodecErrorCode =
  | "LimitExceeded"
  | "Truncated"
  | "TrailingBytes"
  | "InvalidBooleanMarker"
  | "InvalidOptionalMarker"
  | "UnknownTag"
  | "UnknownMessage"
  | "InvalidValue"
  | "SharedArrayBuffer";

export interface PayloadCodecError {
  readonly code: PayloadCodecErrorCode;
  readonly offset: number;
}

export type PayloadCodecResult<T> =
  | Readonly<{ ok: true; value: T }>
  | Readonly<{ ok: false; error: Readonly<PayloadCodecError> }>;

export interface PayloadCodecLimits {
  readonly maxDepth: number;
  readonly maxBytes: number;
  readonly maxContainerItems: number;
}

class PayloadCodecFailure {
  readonly code: PayloadCodecErrorCode;
  readonly offset: number;

  constructor(code: PayloadCodecErrorCode, offset: number) {
    this.code = code;
    this.offset = offset;
  }
}

const payloadCodecOk = <T>(value: T): PayloadCodecResult<T> =>
  Object.freeze({ ok: true as const, value });

const payloadCodecError = <T>(
  code: PayloadCodecErrorCode,
  offset: number,
): PayloadCodecResult<T> => {
  const error = Object.freeze({ code, offset });
  return Object.freeze({ ok: false as const, error });
};

const payloadCodecFailureResult = <T>(failure: unknown): PayloadCodecResult<T> =>
  failure instanceof PayloadCodecFailure
    ? payloadCodecError(failure.code, failure.offset)
    : payloadCodecError("InvalidValue", 0);

const payloadCodecFail = (code: PayloadCodecErrorCode, offset: number): never => {
  throw new PayloadCodecFailure(code, offset);
};

const payloadCodecValidLimit = (value: number): boolean =>
  Number.isSafeInteger(value) && value > 0;

const payloadCodecNormalizeLimits = (
  limits: Readonly<PayloadCodecLimits>,
): Readonly<PayloadCodecLimits> => {
  if (
    typeof limits !== "object"
    || limits === null
    || !payloadCodecValidLimit(limits.maxDepth)
    || !payloadCodecValidLimit(limits.maxBytes)
    || !payloadCodecValidLimit(limits.maxContainerItems)
  ) {
    payloadCodecFail("LimitExceeded", 0);
  }
  return Object.freeze({
    maxDepth: limits.maxDepth,
    maxBytes: limits.maxBytes,
    maxContainerItems: limits.maxContainerItems,
  });
};

const payloadCodecCapBytes = (
  limits: Readonly<PayloadCodecLimits>,
  maximum: number,
): Readonly<PayloadCodecLimits> => Object.freeze({
  maxDepth: limits.maxDepth,
  maxBytes: Math.min(limits.maxBytes, maximum),
  maxContainerItems: limits.maxContainerItems,
});

const payloadCodecSnapshotHeader = (header: EnvelopeHeader): EnvelopeHeader => {
  const candidate = header as unknown as Record<string, unknown>;
  if (
    typeof candidate !== "object"
    || candidate === null
    || !Number.isInteger(candidate.major)
    || Number(candidate.major) < 0
    || Number(candidate.major) > 0xffff
    || !Number.isInteger(candidate.minor)
    || Number(candidate.minor) < 0
    || Number(candidate.minor) > 0xffff
    || !Number.isInteger(candidate.message_type)
    || Number(candidate.message_type) < 0
    || Number(candidate.message_type) > 0xffff
    || !Number.isInteger(candidate.flags)
    || Number(candidate.flags) < 0
    || Number(candidate.flags) > 0xffff
    || !Number.isInteger(candidate.payload_len)
    || Number(candidate.payload_len) < 0
    || Number(candidate.payload_len) > 0xffffffff
    || typeof candidate.sequence !== "bigint"
    || candidate.sequence < 0n
    || candidate.sequence > 0xffffffffffffffffn
  ) {
    return payloadCodecFail("InvalidValue", 0);
  }
  return Object.freeze({
    major: Number(candidate.major),
    minor: Number(candidate.minor),
    message_type: Number(candidate.message_type),
    flags: Number(candidate.flags),
    payload_len: Number(candidate.payload_len),
    sequence: candidate.sequence,
  });
};

const payloadCodecIsSharedArrayBufferView = (value: Uint8Array): boolean =>
  typeof SharedArrayBuffer !== "undefined" && value.buffer instanceof SharedArrayBuffer;

class PayloadWriter {
  private readonly output: number[] = [];
  private readonly limits: Readonly<PayloadCodecLimits>;
  private remainingContainerItems: number;

  constructor(limits: Readonly<PayloadCodecLimits>) {
    this.limits = payloadCodecNormalizeLimits(limits);
    this.remainingContainerItems = this.limits.maxContainerItems;
  }

  get offset(): number {
    return this.output.length;
  }

  checkDepth(depth: number): void {
    if (!Number.isSafeInteger(depth) || depth < 0 || depth > this.limits.maxDepth) {
      payloadCodecFail("LimitExceeded", this.offset);
    }
  }

  private chargeContainer(count: number): void {
    if (!Number.isSafeInteger(count) || count < 0 || count > this.remainingContainerItems) {
      payloadCodecFail("LimitExceeded", this.offset);
    }
    this.remainingContainerItems -= count;
  }

  private writeRaw(bytes: ArrayLike<number>): void {
    const length = this.output.length + bytes.length;
    if (!Number.isSafeInteger(length) || length > this.limits.maxBytes) {
      payloadCodecFail("LimitExceeded", this.offset);
    }
    for (let index = 0; index < bytes.length; index += 1) {
      this.output.push(Number(bytes[index]));
    }
  }

  writeU8(value: number): void {
    if (!isU8(value)) {
      payloadCodecFail("InvalidValue", this.offset);
    }
    this.writeRaw([value]);
  }

  writeU16(value: number): void {
    if (!Number.isInteger(value) || value < 0 || value > 0xffff) {
      payloadCodecFail("InvalidValue", this.offset);
    }
    this.writeRaw([value & 0xff, (value >>> 8) & 0xff]);
  }

  writeU32(value: number): void {
    if (!Number.isInteger(value) || value < 0 || value > 0xffffffff) {
      payloadCodecFail("InvalidValue", this.offset);
    }
    this.writeRaw([
      value & 0xff,
      (value >>> 8) & 0xff,
      (value >>> 16) & 0xff,
      Math.floor(value / 0x1000000) & 0xff,
    ]);
  }

  writeU64(value: bigint): void {
    if (typeof value !== "bigint" || value < 0n || value > 0xffffffffffffffffn) {
      payloadCodecFail("InvalidValue", this.offset);
    }
    const bytes = new Array<number>(8);
    let remaining = value;
    for (let index = 0; index < 8; index += 1) {
      bytes[index] = Number(remaining & 0xffn);
      remaining >>= 8n;
    }
    this.writeRaw(bytes);
  }

  writeI32(value: number): void {
    if (!Number.isInteger(value) || value < -0x80000000 || value > 0x7fffffff) {
      payloadCodecFail("InvalidValue", this.offset);
    }
    this.writeU32(value < 0 ? value + 0x100000000 : value);
  }

  writeBool(value: boolean): void {
    if (typeof value !== "boolean") {
      payloadCodecFail("InvalidValue", this.offset);
    }
    this.writeU8(value ? 1 : 0);
  }

  writeOptional(present: boolean): void {
    if (present) {
      this.chargeContainer(1);
    }
    this.writeU8(present ? 1 : 0);
  }

  writeCount(count: number, maximum: number): void {
    if (
      !Number.isInteger(count)
      || count < 0
      || count > maximum
      || count > 0xffffffff
    ) {
      payloadCodecFail("LimitExceeded", this.offset);
    }
    this.chargeContainer(count);
    this.writeU32(count);
  }

  writeFixed(value: Uint8Array, length: number): void {
    if (!(value instanceof Uint8Array) || value.byteLength !== length) {
      payloadCodecFail("InvalidValue", this.offset);
    }
    if (payloadCodecIsSharedArrayBufferView(value)) {
      payloadCodecFail("SharedArrayBuffer", this.offset);
    }
    this.writeRaw(value);
  }

  writeBytes(value: Uint8Array, maximum: number): void {
    if (!(value instanceof Uint8Array)) {
      payloadCodecFail("InvalidValue", this.offset);
    }
    if (payloadCodecIsSharedArrayBufferView(value)) {
      payloadCodecFail("SharedArrayBuffer", this.offset);
    }
    this.writeCount(value.byteLength, maximum);
    this.writeRaw(value);
  }

  finish(): Uint8Array {
    return Uint8Array.from(this.output);
  }
}

class PayloadReader {
  private readonly input: Uint8Array;
  private readonly limits: Readonly<PayloadCodecLimits>;
  private position = 0;
  private remainingContainerItems: number;

  constructor(input: Uint8Array, limits: Readonly<PayloadCodecLimits>) {
    this.limits = payloadCodecNormalizeLimits(limits);
    if (!(input instanceof Uint8Array)) {
      payloadCodecFail("InvalidValue", 0);
    }
    if (payloadCodecIsSharedArrayBufferView(input)) {
      payloadCodecFail("SharedArrayBuffer", 0);
    }
    if (input.byteLength > this.limits.maxBytes) {
      payloadCodecFail("LimitExceeded", 0);
    }
    this.input = Uint8Array.from(input);
    this.remainingContainerItems = this.limits.maxContainerItems;
  }

  get offset(): number {
    return this.position;
  }

  checkDepth(depth: number): void {
    if (!Number.isSafeInteger(depth) || depth < 0 || depth > this.limits.maxDepth) {
      payloadCodecFail("LimitExceeded", this.offset);
    }
  }

  private chargeContainer(count: number): void {
    if (!Number.isSafeInteger(count) || count < 0 || count > this.remainingContainerItems) {
      payloadCodecFail("LimitExceeded", this.offset);
    }
    this.remainingContainerItems -= count;
  }

  private take(count: number): Uint8Array {
    const end = this.position + count;
    if (!Number.isSafeInteger(end) || count < 0 || end > this.input.byteLength) {
      payloadCodecFail("Truncated", this.position);
    }
    const bytes = this.input.subarray(this.position, end);
    this.position = end;
    return bytes;
  }

  readU8(): number {
    return Number(this.take(1)[0]);
  }

  readU16(): number {
    const bytes = this.take(2);
    return Number(bytes[0]) | (Number(bytes[1]) << 8);
  }

  readU32(): number {
    const bytes = this.take(4);
    return (
      Number(bytes[0])
      + Number(bytes[1]) * 0x100
      + Number(bytes[2]) * 0x10000
      + Number(bytes[3]) * 0x1000000
    );
  }

  readU64(): bigint {
    const bytes = this.take(8);
    let value = 0n;
    for (let index = 7; index >= 0; index -= 1) {
      value = (value << 8n) | BigInt(Number(bytes[index]));
    }
    return value;
  }

  readI32(): number {
    const value = this.readU32();
    return value > 0x7fffffff ? value - 0x100000000 : value;
  }

  readBool(): boolean {
    const offset = this.offset;
    const marker = this.readU8();
    if (marker === 0) return false;
    if (marker === 1) return true;
    return payloadCodecFail("InvalidBooleanMarker", offset);
  }

  readOptional(): boolean {
    const offset = this.offset;
    const marker = this.readU8();
    if (marker === 0) return false;
    if (marker === 1) {
      this.chargeContainer(1);
      return true;
    }
    return payloadCodecFail("InvalidOptionalMarker", offset);
  }

  readFixed(length: number): Uint8Array {
    return Uint8Array.from(this.take(length));
  }

  readCount(maximum: number, minimumItemBytes: number): number {
    const countOffset = this.offset;
    const count = this.readU32();
    if (count > maximum) {
      payloadCodecFail("LimitExceeded", countOffset);
    }
    this.chargeContainer(count);
    const minimum = count * minimumItemBytes;
    if (!Number.isSafeInteger(minimum)) {
      payloadCodecFail("LimitExceeded", countOffset);
    }
    if (minimum > this.input.byteLength - this.position) {
      payloadCodecFail("Truncated", this.position);
    }
    return count;
  }

  readBytes(maximum: number): Uint8Array {
    const count = this.readCount(maximum, 1);
    return Uint8Array.from(this.take(count));
  }

  finish(): void {
    if (this.position !== this.input.byteLength) {
      payloadCodecFail("TrailingBytes", this.position);
    }
  }
}

const payloadCodecEncodeRoot = <T>(
  value: T,
  limits: Readonly<PayloadCodecLimits>,
  encode: (value: T, depth: number, writer: PayloadWriter) => void,
): PayloadCodecResult<Uint8Array> => {
  try {
    const writer = new PayloadWriter(limits);
    encode(value, 0, writer);
    return payloadCodecOk(writer.finish());
  } catch (failure: unknown) {
    return payloadCodecFailureResult(failure);
  }
};

const payloadCodecDecodeRoot = <T>(
  input: Uint8Array,
  limits: Readonly<PayloadCodecLimits>,
  decode: (depth: number, reader: PayloadReader) => T,
): PayloadCodecResult<T> => {
  try {
    const reader = new PayloadReader(input, limits);
    const value = decode(0, reader);
    reader.finish();
    return payloadCodecOk(value);
  } catch (failure: unknown) {
    return payloadCodecFailureResult(failure);
  }
};
