  reader.checkDepth(depth);
  const payload_decision_schema_version = reader.readU16();
  const payload_status = payloadDecodeSupportStatusFrom(depth + 1, reader);
  const payload_profile = payloadDecodeCapabilityProfileIdFrom(depth + 1, reader);
  const payload_profile_version = reader.readU32();
  const payload_policy_version = reader.readU32();
  const payload_subject = payloadDecodeCapabilitySubjectFrom(depth + 1, reader);
  const payload_missing = (() => { const payloadCount = reader.readCount(16, 40); const payloadValues = []; for (let index = 0; index < payloadCount; index += 1) payloadValues.push(payloadDecodeCapabilityRequirementFrom(depth + 1 + 1, reader)); return Object.freeze(payloadValues) as unknown as CapabilityRequirement[]; })();
  const payload_missing_total = reader.readU32();
