function payloadEncodeReadyEventInto(value: ReadyEvent, depth: number, writer: PayloadWriter): void {
  writer.checkDepth(depth);
  payloadEncodeWorkerIdInto(value.worker, depth + 1, writer);
  writer.writeU16(value.negotiated_minor);
  writer.writeFixed(value.schema_hash, 16);
  payloadEncodeEngineExecutionCapabilitiesInto(value.execution_capabilities, depth + 1, writer);
  {
    const payloadList = value.capability_profiles;
    if (!Array.isArray(payloadList)) payloadCodecFail("InvalidValue", writer.offset);
    writer.writeCount(payloadList.length, 8);
    for (const payloadItem of payloadList) {
      payloadEncodeCapabilityProfileIdInto(payloadItem, depth + 1 + 1, writer);
    }
  }
  {
    const payloadList = value.output_profiles;
    if (!Array.isArray(payloadList)) payloadCodecFail("InvalidValue", writer.offset);
    writer.writeCount(payloadList.length, 8);
    for (const payloadItem of payloadList) {
      payloadEncodeOutputProfileInto(payloadItem, depth + 1 + 1, writer);
    }
  }
}

function payloadDecodeReadyEventFrom(depth: number, reader: PayloadReader): ReadyEvent {
  reader.checkDepth(depth);
  const payload_worker = payloadDecodeWorkerIdFrom(depth + 1, reader);
  const payload_negotiated_minor = reader.readU16();
  const payload_schema_hash = reader.readFixed(16);
  const payload_execution_capabilities = payloadDecodeEngineExecutionCapabilitiesFrom(depth + 1, reader);
  const payload_capability_profiles = (() => { const payloadCount = reader.readCount(8, 4); const payloadValues = []; for (let index = 0; index < payloadCount; index += 1) payloadValues.push(payloadDecodeCapabilityProfileIdFrom(depth + 1 + 1, reader)); return Object.freeze(payloadValues) as unknown as CapabilityProfileId[]; })();
  const payload_output_profiles = (() => { const payloadCount = reader.readCount(8, 2); const payloadValues = []; for (let index = 0; index < payloadCount; index += 1) payloadValues.push(payloadDecodeOutputProfileFrom(depth + 1 + 1, reader)); return Object.freeze(payloadValues) as unknown as OutputProfile[]; })();
  return Object.freeze({
    worker: payload_worker,
    negotiated_minor: payload_negotiated_minor,
    schema_hash: payload_schema_hash,
    execution_capabilities: payload_execution_capabilities,
    capability_profiles: payload_capability_profiles,
    output_profiles: payload_output_profiles,
  }) as ReadyEvent;
}

