function payloadEncodeNeedDataEventInto(value: NeedDataEvent, depth: number, writer: PayloadWriter): void {
  writer.checkDepth(depth);
  payloadEncodeDataTicketInto(value.ticket, depth + 1, writer);
  payloadEncodeSourceIdentityInto(value.source, depth + 1, writer);
  {
    const payloadList = value.ranges;
    if (!Array.isArray(payloadList)) payloadCodecFail("InvalidValue", writer.offset);
    writer.writeCount(payloadList.length, 16);
    for (const payloadItem of payloadList) {
      payloadEncodeByteRangeInto(payloadItem, depth + 1 + 1, writer);
    }
  }
  payloadEncodeDataPriorityInto(value.priority, depth + 1, writer);
  writer.writeU64(value.checkpoint);
}

function payloadDecodeNeedDataEventFrom(depth: number, reader: PayloadReader): NeedDataEvent {
  reader.checkDepth(depth);
  const payload_ticket = payloadDecodeDataTicketFrom(depth + 1, reader);
  const payload_source = payloadDecodeSourceIdentityFrom(depth + 1, reader);
  const payload_ranges = (() => { const payloadCount = reader.readCount(16, 16); const payloadValues = []; for (let index = 0; index < payloadCount; index += 1) payloadValues.push(payloadDecodeByteRangeFrom(depth + 1 + 1, reader)); return Object.freeze(payloadValues) as unknown as ByteRange[]; })();
  const payload_priority = payloadDecodeDataPriorityFrom(depth + 1, reader);
  const payload_checkpoint = reader.readU64();
  return Object.freeze({
    ticket: payload_ticket,
    source: payload_source,
    ranges: payload_ranges,
    priority: payload_priority,
    checkpoint: payload_checkpoint,
  }) as NeedDataEvent;
}

