function payloadEncodeSurfaceTransportInto(value: SurfaceTransport, depth: number, writer: PayloadWriter): void {
  writer.checkDepth(depth);
  switch (value.kind) {
    case "BrowserArrayBuffer":
      writer.writeU8(1);
      writer.writeU16(value.slot);
      writer.writeU64(value.buffer_length);
      return;
    case "BrowserImageBitmap":
      writer.writeU8(2);
      writer.writeU16(value.slot);
      writer.writeU32(value.width);
      writer.writeU32(value.height);
      return;
    case "BrowserSharedArrayBuffer":
      writer.writeU8(3);
      writer.writeU16(value.attachment_slot);
      writer.writeU64(value.buffer_length);
      writer.writeU64(value.fence_byte_offset);
      writer.writeU32(value.publication_epoch);
      return;
    default: return payloadCodecFail("InvalidValue", writer.offset);
  }
}

function payloadDecodeSurfaceTransportFrom(depth: number, reader: PayloadReader): SurfaceTransport {
  reader.checkDepth(depth);
  const tagOffset = reader.offset;
  const tag = reader.readU8();
  switch (tag) {
    case 1:
      return Object.freeze({
        kind: "BrowserArrayBuffer" as const,
        slot: reader.readU16(),
        buffer_length: reader.readU64(),
      }) as SurfaceTransport;
    case 2:
      return Object.freeze({
        kind: "BrowserImageBitmap" as const,
        slot: reader.readU16(),
        width: reader.readU32(),
        height: reader.readU32(),
      }) as SurfaceTransport;
    case 3:
      return Object.freeze({
        kind: "BrowserSharedArrayBuffer" as const,
        attachment_slot: reader.readU16(),
        buffer_length: reader.readU64(),
        fence_byte_offset: reader.readU64(),
        publication_epoch: reader.readU32(),
      }) as SurfaceTransport;
    default: return payloadCodecFail("UnknownTag", tagOffset);
  }
}

