const payloadCodecHashPreimage = (
  domain: string,
  payload: Uint8Array,
): PayloadCodecResult<Uint8Array> => {
  try {
    const domainBytes = new TextEncoder().encode(domain);
    const lengthOffset = domainBytes.byteLength + 1;
    const payloadOffset = lengthOffset + 8;
    const totalLength = payloadOffset + payload.byteLength;
    if (!Number.isSafeInteger(totalLength)) return payloadCodecError("LimitExceeded", 0);
    const preimage = new Uint8Array(totalLength);
    preimage.set(domainBytes, 0);
    preimage[domainBytes.byteLength] = 0;
    let payloadLength = BigInt(payload.byteLength);
    for (let index = 0; index < 8; index += 1) {
      preimage[lengthOffset + index] = Number(payloadLength & 0xffn);
      payloadLength >>= 8n;
    }
    preimage.set(payload, payloadOffset);
    return payloadCodecOk(preimage);
  } catch (failure: unknown) {
    return payloadCodecFailureResult(failure);
  }
};

export function capabilityDecisionHashPreimage(value: CapabilityDecision, limits: Readonly<PayloadCodecLimits> = DEFAULT_PAYLOAD_CODEC_LIMITS): PayloadCodecResult<Uint8Array> {
  const encoded = encodeCapabilityDecisionPayload(value, limits);
  if (!encoded.ok) return encoded;
  return payloadCodecHashPreimage(CAPABILITY_DECISION_HASH_DOMAIN, encoded.value);
}

export function renderPlanManifestHashPreimage(value: RenderPlanManifest, limits: Readonly<PayloadCodecLimits> = DEFAULT_PAYLOAD_CODEC_LIMITS): PayloadCodecResult<Uint8Array> {
  const encoded = encodeRenderPlanManifestPayload(value, limits);
  if (!encoded.ok) return encoded;
  return payloadCodecHashPreimage(RENDER_PLAN_MANIFEST_HASH_DOMAIN, encoded.value);
}
